export function searchEnrichedProcedures(query: string): EnrichedProcedure[] {
  if (!query || !query.trim()) return ENRICHED_PROCEDURES
  const q = query.trim().toLowerCase()
  return ENRICHED_PROCEDURES.filter(p =>
    p.title.toLowerCase().includes(q) ||
    p.ministry.toLowerCase().includes(q) ||
    p.description.toLowerCase().includes(q) ||
    p.steps.some(s => s.toLowerCase().includes(q)) ||
    p.requiredDocuments.some(d => d.toLowerCase().includes(q))
  )
}

export function getEnrichedProcedure(code: string): EnrichedProcedure | undefined {
  return ENRICHED_PROCEDURES.find(p => p.code === code)
}
